        return nil, fmt.Errorf("relative_time_range is missing or invalid")
    }

    rtrMap, ok := listShim[0].(map[string]any)
    if !ok {
         return nil, fmt.Errorf("relative_time_range entry is not a map")
    }

    // ... proceed with rtrMap
}
```

2. Check the call path in the Crossplane provider and investigate why there is no prior validation of CR input. It might be a Crossplane / Upjet limitation though since the bulk of the wrapper code is auto generated.

